// Parse CSV content into individual signal objects.
// CSV format:
//   source,symbol,direction,conviction,valid_from,valid_until,headline,raw_url,tags
// tags column: semicolon-separated list (e.g. momentum;swing)

const csvContent = $input.item.json.csv_content || '';
const lines = csvContent.trim().split('\n');

if (lines.length < 2) {
  throw new Error('CSV must have a header row and at least one data row');
}

const headers = lines[0].split(',').map(h => h.trim());
const requiredCols = ['source', 'symbol', 'direction', 'valid_from'];
for (const col of requiredCols) {
  if (!headers.includes(col)) throw new Error(`Missing required CSV column: ${col}`);
}

const signals = [];
for (let i = 1; i < lines.length; i++) {
  const line = lines[i].trim();
  if (!line) continue;

  const values = line.split(',');
  const row = {};
  headers.forEach((h, idx) => { row[h] = (values[idx] || '').trim(); });

  if (!row.source || !row.symbol || !row.direction || !row.valid_from) {
    console.log(`Skipping row ${i}: missing required fields`);
    continue;
  }

  signals.push({
    source: row.source,
    symbol: row.symbol.toUpperCase(),
    direction: row.direction.toLowerCase(),
    conviction: row.conviction ? parseFloat(row.conviction) : 0.5,
    valid_from: row.valid_from,
    valid_until: row.valid_until || null,
    headline: row.headline || '',
    raw_url: row.raw_url || '',
    tags: row.tags ? row.tags.split(';').map(t => t.trim()).filter(Boolean) : [],
  });
}

console.log(`Parsed ${signals.length} signals from CSV`);
return signals.map(s => ({ json: s }));

// Collect and summarize ingestion results.
const items = $input.all();
const succeeded = items.filter(i => i.json.signal_id || i.json.id).length;
const failed = items.length - succeeded;

console.log(`CSV ingest complete: ${succeeded} succeeded, ${failed} failed`);

return [{
  json: {
    total: items.length,
    succeeded,
    failed,
    results: items.map(i => i.json),
  }
}];
